"""
Reproducibly rebuild the OpenV2G EXI encoder/decoder from the bundled
``vendor/OpenV2Gx/`` submodule, producing an executable we can drop into
``hotwire/exi/codec/``.

Why this exists instead of invoking the upstream Makefile:

  * The upstream Makefile was generated by Eclipse CDT and assumes the
    MinGW C linker is on PATH as ``gcc``, which is not true on a typical
    Windows dev box. It also hardcodes the ``.exe`` suffix.
  * We want the same script to work on Linux and macOS without editing.
  * We want to be able to point the build at any gcc-compatible compiler
    (MSYS2, the one bundled with Vagrant, Apple clang, apt-installed gcc)
    via one env var — ``HOTWIRE_CC`` — or auto-detection.

The resulting binary is called ``OpenV2G.exe`` on Windows and ``OpenV2G``
elsewhere, matching the path-resolution logic in
``hotwire/exi/connector.py``.

Usage:
    python vendor/build_openv2g.py            # auto-detect compiler
    python vendor/build_openv2g.py --cc gcc   # force compiler
    python vendor/build_openv2g.py --dry-run  # show commands but don't run

Upstream: https://github.com/uhi22/OpenV2Gx (LGPL-3.0, Siemens AG 2007-2022).
"""
from __future__ import annotations

import argparse
import os
import shutil
import subprocess
import sys
from pathlib import Path

VENDOR_ROOT = Path(__file__).resolve().parent
OPENV2G_ROOT = VENDOR_ROOT / "OpenV2Gx"
SRC_ROOT = OPENV2G_ROOT / "src"
BUILD_DIR = VENDOR_ROOT / "_build_openv2g"
CODEC_DIR = VENDOR_ROOT.parent / "hotwire" / "exi" / "codec"

# Every include directory that any .c file might reference.
INCLUDE_SUBDIRS = [
    "appHandshake", "codec", "din", "iso1", "iso2",
    "test", "transport", "xmldsig",
]

# Matches the upstream Eclipse Release configuration — -Os size opt,
# all warnings, stop-on-newline-free messages, and the msys2/mingw
# defaults.
CFLAGS = ["-Os", "-Wall", "-fmessage-length=0"]


def _auto_detect_cc() -> str | None:
    """Pick a usable compiler. Prefers env var, then PATH, then well-known
    Windows dev kit locations."""
    env = os.environ.get("HOTWIRE_CC")
    if env:
        return env
    for candidate in ("gcc", "clang", "x86_64-w64-mingw32-gcc"):
        path = shutil.which(candidate)
        if path:
            return path
    # Windows fallbacks — several tools ship a private mingw64. Ordered
    # by likelihood of having a complete runtime (MSYS2 UCRT64 > MinGW64 >
    # Vagrant-embedded > anaconda).
    if os.name == "nt":
        for guess in (
            r"C:\msys64\ucrt64\bin\gcc.exe",
            r"C:\msys64\mingw64\bin\gcc.exe",
            r"C:\Ruby34-x64\msys64\ucrt64\bin\gcc.exe",
            r"C:\Ruby34-x64\msys64\mingw64\bin\gcc.exe",
            r"C:\mingw64\bin\gcc.exe",
            r"C:\Program Files\Vagrant\embedded\mingw64\bin\gcc.exe",
            r"C:\Users\sickcell\anaconda3\Library\mingw-w64\bin\gcc.exe",
        ):
            if Path(guess).is_file():
                return guess
    return None


def _gather_sources() -> list[Path]:
    srcs: list[Path] = []
    for p in SRC_ROOT.rglob("*.c"):
        # Skip the upstream "test" entry-point files — we only want the
        # library + the main.c that the pyPLC fork provides. The CLI entry
        # is src/test/main.c; keep it.
        srcs.append(p)
    return sorted(srcs)


def _include_flags() -> list[str]:
    return [f"-I{SRC_ROOT / sub}" for sub in INCLUDE_SUBDIRS]


def _output_binary_path() -> Path:
    name = "OpenV2G.exe" if os.name == "nt" else "OpenV2G"
    return BUILD_DIR / name


def _build_env(cc: str) -> dict[str, str]:
    """Return an env dict that ensures the compiler's own runtime DLLs
    resolve. MSYS2/MinGW gcc silently aborts with rc=1 (no stderr) when
    its libwinpthread-1.dll or libgcc_s_seh-1.dll can't be found, which
    happens when only the .exe is on PATH but its bin/ dir isn't.
    """
    env = os.environ.copy()
    cc_dir = str(Path(cc).parent)
    if cc_dir not in env.get("PATH", "").split(os.pathsep):
        env["PATH"] = cc_dir + os.pathsep + env.get("PATH", "")
    return env


PATCHES_DIR = VENDOR_ROOT / "patches"


def _apply_patches(dry_run: bool = False) -> None:
    """Apply every ``*.patch`` file under ``vendor/patches/`` to the
    submodule, skipping patches that are already applied. Keeping the
    patches as files (rather than committing into the submodule) means
    the submodule pointer stays at an upstream-released commit and
    HotWire's local modifications are visible in diff form."""
    if not PATCHES_DIR.is_dir():
        return
    patches = sorted(PATCHES_DIR.glob("*.patch"))
    if not patches:
        return
    for patch in patches:
        # Check whether the patch is already applied — if yes, skip.
        check = subprocess.run(
            ["git", "apply", "--check", "-R", str(patch)],
            cwd=OPENV2G_ROOT,
            capture_output=True,
            text=True,
        )
        if check.returncode == 0:
            print(f"[patch] {patch.name} already applied, skipping")
            continue
        print(f"[patch] applying {patch.name}")
        if dry_run:
            continue
        result = subprocess.run(
            ["git", "apply", "--whitespace=nowarn", str(patch)],
            cwd=OPENV2G_ROOT,
            capture_output=True,
            text=True,
        )
        if result.returncode != 0:
            sys.stderr.write(result.stdout)
            sys.stderr.write(result.stderr)
            raise SystemExit(f"[patch] failed to apply {patch}")


def build(cc: str, dry_run: bool = False) -> Path:
    if not OPENV2G_ROOT.is_dir():
        raise SystemExit(
            f"[openv2g] {OPENV2G_ROOT} missing. Did you clone the submodule?\n"
            f"  git submodule update --init --recursive"
        )

    _apply_patches(dry_run=dry_run)

    sources = _gather_sources()
    if not sources:
        raise SystemExit(f"[openv2g] no .c files found under {SRC_ROOT}")

    BUILD_DIR.mkdir(exist_ok=True)
    obj_files: list[Path] = []
    includes = _include_flags()
    env = _build_env(cc)

    for src in sources:
        obj = BUILD_DIR / (src.stem + ".o")
        cmd = [cc, *CFLAGS, *includes, "-c", str(src), "-o", str(obj)]
        print(f"[cc] {src.name}", flush=True)
        if dry_run:
            print("     " + " ".join(cmd))
        else:
            result = subprocess.run(cmd, capture_output=True, text=True, env=env)
            if result.returncode != 0:
                sys.stderr.write(result.stdout)
                sys.stderr.write(result.stderr)
                raise SystemExit(f"[openv2g] compile failed on {src}")
        obj_files.append(obj)

    output = _output_binary_path()
    link_cmd = [cc, "-o", str(output), *[str(o) for o in obj_files]]
    print(f"[link] {output.name}", flush=True)
    if dry_run:
        print("     " + " ".join(link_cmd))
        return output

    result = subprocess.run(link_cmd, capture_output=True, text=True, env=env)
    if result.returncode != 0:
        sys.stderr.write(result.stdout)
        sys.stderr.write(result.stderr)
        raise SystemExit("[openv2g] link failed")

    print(f"[ok] produced {output} ({output.stat().st_size} bytes)")
    return output


def install(binary: Path) -> None:
    """Copy the freshly-built binary into hotwire/exi/codec/."""
    CODEC_DIR.mkdir(parents=True, exist_ok=True)
    dest = CODEC_DIR / binary.name
    shutil.copy2(binary, dest)
    try:
        os.chmod(dest, 0o755)
    except OSError:
        pass
    print(f"[install] {binary} -> {dest}")


def main() -> int:
    parser = argparse.ArgumentParser(description="Rebuild OpenV2G from source.")
    parser.add_argument("--cc", help="Compiler to use (defaults to gcc on PATH).")
    parser.add_argument("--dry-run", action="store_true",
                        help="Print commands without executing.")
    parser.add_argument("--no-install", action="store_true",
                        help="Don't copy the binary into hotwire/exi/codec/.")
    args = parser.parse_args()

    cc = args.cc or _auto_detect_cc()
    if not cc:
        raise SystemExit(
            "[openv2g] no C compiler found. Set HOTWIRE_CC or pass --cc."
        )
    print(f"[openv2g] using compiler: {cc}")

    binary = build(cc, dry_run=args.dry_run)
    if not args.dry_run and not args.no_install:
        install(binary)
    return 0


if __name__ == "__main__":
    sys.exit(main())
